_shaderData.warp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


vec2 uv1 = (vUv-.5);// * uAspect.xy;

vec2 uv6 = uv1;
float z = 14*length((abs(uv1.x)-abs(uv1.y)));
vec2 d = normalize(uv1);
vec2 rs = clamp(tan(z)*d,-2,2);
uv1 -= rs/40;

uv6 = .4*cos(uv1*4);
mus = .003/(length(uv6));
mus *= (1+roam_cos);

vec3 crisp= texture(sampler_main,(uv1)*(.95-q28/16+.4*z)+.5);

vec3 ret1 = crisp + mus;

ret = (ret1*.99-.025);


  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

uvo = vUv;
vUv = multiply(vUv*uAspect.xy,mat2(_qa));

vUv = vUv + -.0- .1*vec2(q5,q6);
vec2 uv1 = (vUv-.5 );//*uAspect.xy;

//Kugel1
rsk = (uv1 + vec2 (q9,q10)) ;
dz1 = normalize(rsk);
rad1 = q11*length(rsk) ;
uv4 =  tan(rad1)*dz1;
mask1 = clamp01(8-8*rad1);
Kugel1 = uv4*mask1;

//Kugel2
rsk = (uv1 + vec2 (q13,q14)) ;
dz2 = normalize(rsk);
rad2 = q15*length(rsk) ;
uv4 =  tan(rad2)*dz2;
mask2 = clamp01(8-8*rad2);
Kugel2 = uv4*mask2;

//Kugel3
rsk = (uv1 + vec2 (q17,q18)) ;
dz3 = normalize(rsk);
rad3 = q19*length(rsk) ;
uv4 =  tan(rad3)*dz3;
mask3 = clamp01(8-8*rad3);
Kugel3 = uv4*mask3;

vec2 dz = (Kugel2 + Kugel1 + Kugel3)*.2;
//******************** STARS
uv1 += dz;
rss0.x = atan(uv1.x, uv1.y)/3.1416;
rss0.y = .1*q21/(length(uv1));

rss = vec2 (rss0.x,rss0.y+uTime);
rss = multiply(rss,mat2(.7,.7,-.7,.7));
float noise = (texture(sampler_pw_noise_lq,rss/32)-.5 >= 0);
tmp = abs(fract(rss*8)-.5);
vec3 dots = clamp01(.04/length(tmp)) *noise;

rss = vec2 (rss0.x,rss0.y+uTime/4);
rss = multiply(rss,mat2(.7,.7,-.7,.7));
noise = (texture(sampler_pw_noise_lq,rss/32)-.5 >= 0);
tmp = abs(fract(rss*8)-.5);
dots += clamp01(.02/length(tmp)) * noise;

dots *= clamp01(.2/abs(rss0.y));
dots *= dots*.6;
//*************************

float z = q32/(uv1.y-.02);//floor proxy
float mask = clamp01(4/z);
rs0.x = (uv1.x)*z;
rs0.y = z/4;
rs.x = rs0.x ;
rs.y = rs0.y + q8*3;
vec3 mirror = lum(texture(sampler_pw_noise_lq,.02*rs))-.5;
z = .2/(length(uv1)-q21);
uv2.y = z + q8;
uv2.x = rss0.x +q7;
uv3 =fract(uv2 +.0*mask*mirror);

ret1 =  texture(sampler_main,uv3)/z;
ret = max(ret1*(1-0.5*mask),mirror*mask) +dots;

float mod = q22*2;
vec3 blk = abs(inversesqrt(rad1)*dz1.x*roam_sin
+inversesqrt(rad2)*dz2.y*roam_sin.rbg
+inversesqrt(rad3)*dz3.x*roam_sin.bgr)*(.2+mirror*mask)*mod;
ret += blk;

ret2 = clamp01(.02*q22*q21/length(uv1)*
 (lum(texture(sampler_main,uv1+.5))));
ret2 /= (length(uv1)+.02);
float k1 = lum(ret2);
ret += k1*vec3(1,k1,k1/2)  ;

  fragColor = ret;
}
